SecurityAlert
| where TimeGenerated {TimeRange}
| where AlertName has "UniFi"
| summarize Count = count(
    ) by AlertName
| order by Count desc

CommonSecurityLog
| where DeviceVendor =~ "Ubiquiti"
| where TimeGenerated {TimeRange}
| where SourceIP == "{TargetIP}"
| summarize Events = count(
    ) by bin(TimeGenerated, 10m), DeviceAction

CommonSecurityLog
| where DeviceVendor =~ "Ubiquiti"
| where DeviceEventClassID in ("sshd_auth_success", "sshd_auth_fail"
    )
| where TimeGenerated {TimeRange}
| summarize Events = count() by bin(TimeGenerated, 5m), DeviceEventClassID
